// Tokens de cor das variações (alinhados ao DSS)
const VARIANTS = {
  default: {
    smartMeterColor: "#a4a6a5",
    sansysColor: "#a4a6a5",
    iconColor: "#a4a6a5",
  },
  colored: {
    smartMeterColor: "#224a99", // azul
    sansysColor: "#1d4971", // azul escuro
    iconColor: "#224a99", // azul (mesmo tom do SmartMeter)
  },
} as const;

export type LogoVariant = keyof typeof VARIANTS;

export interface SansysSmartMeterLogoProps {
  className?: string;
  /** Preset de cores. 'default' = monocromático neutro, 'colored' = cores da marca. */
  variant?: LogoVariant;
  /**
   * Cor do wordmark "SmartMeter".
   * Sobrepõe a cor definida pelo variant.
   */
  smartMeterColor?: string;
  /**
   * Cor do wordmark "Sansys".
   * Sobrepõe a cor definida pelo variant.
   */
  sansysColor?: string;
  /**
   * Cor do ícone.
   * Sobrepõe a cor definida pelo variant.
   */
  iconColor?: string;
  /**
   * @deprecated Use `smartMeterColor` + `sansysColor` + `iconColor` para controle granular,
   * ou `variant` para presets. Mantido por compatibilidade.
   */
  color?: string;
}

export function SansysSmartMeterLogo({
  className = "h-12",
  variant = "default",
  smartMeterColor,
  sansysColor,
  iconColor,
  color, // legacy
}: SansysSmartMeterLogoProps) {
  const base = VARIANTS[variant];

  // Resolução de cor: prop explícita > legacy `color` > valor do variant
  const resolvedSmartMeter = smartMeterColor ?? color ?? base.smartMeterColor;
  const resolvedSansys = sansysColor ?? color ?? base.sansysColor;
  const resolvedIcon = iconColor ?? color ?? base.iconColor;

  return (
    <svg
      className={className}
      viewBox="0 0 97 42"
      xmlns="http://www.w3.org/2000/svg"
      aria-label="Sansys SmartMeter"
      role="img"
    >
      <g>
        {/* Ícone: símbolo do medidor inteligente */}
        <path fill={resolvedIcon} d={ICON_PATH} />

        {/* Wordmark: SmartMeter */}
        <path fill={resolvedSmartMeter} d={SMARTMETER_PATH} />

        {/* Wordmark: Sansys */}
        <path fill={resolvedSansys} d={SANSYS_PATH} />
      </g>
    </svg>
  );
}
